import type { Quantity } from "../../../core/quantity.js";
import type { AngleUnit, AreaUnit, LengthUnit } from "../../../core/units.js";

/** @internal */
export interface InputUnitInfo<T extends Quantity["unit"]> {}

/**
 * Information about units to use for various measurement types.
 *
 * @internal
 */
export interface InputUnitInfos {
  /** @internal */
  length: InputUnitInfo<LengthUnit>;
  /** @internal */
  verticalLength: InputUnitInfo<LengthUnit>;
  /** @internal */
  area: InputUnitInfo<AreaUnit>;
  /** @internal */
  angle: InputUnitInfo<AngleUnit>;
}